from flask import Flask, request, jsonify, session
import random
import string

app = Flask(__name__)
app.secret_key = 'your_secret_key'

users_db = {
    'user1': {'password': 'password123', 'mfa_enabled': True, 'otp': None},
    'user2': {'password': 'securepass', 'mfa_enabled': False, 'otp': None}
}

def generate_otp():
    return ''.join(random.choices(string.digits, k=6))

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    if username not in users_db or users_db[username]['password'] != password:
        return jsonify({'message': 'Invalid credentials'}), 401

    if users_db[username]['mfa_enabled']:
        otp = generate_otp()
        users_db[username]['otp'] = otp
        session['username'] = username
        return jsonify({'message': 'MFA enabled, OTP sent', 'otp': otp})
    
    session['username'] = username
    return jsonify({'message': 'Access granted'})

@app.route('/verify-otp', methods=['POST'])
def verify_otp():
    username = session.get('username')
    if not username:
        return jsonify({'message': 'Session expired'}), 401
    
    otp = request.json.get('otp')
    if users_db[username]['otp'] == otp:
        users_db[username]['otp'] = None
        session.pop('username', None)
        return jsonify({'message': 'Access granted'})
    
    return jsonify({'message': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    if username in users_db and users_db[username]['password'] == password:
        return jsonify({'message': 'Direct access granted'})
    
    return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)